mapper.select:
SELECT , u.nickname as author_name, u.avatar as author_avatar, c.name as category_name FROM article a INNER JOIN article_tag at ON a.id = at.article_id LEFT JOIN user u ON a.author_id = u.id LEFT JOIN category c ON a.category_id = c.id
at.tag_id = #{tagId}
AND a.status = #{status}
ORDER BY a.is_top DESC, a.publish_time DESC

SELECT , u.nickname as author_name, u.avatar as author_avatar, c.name as category_name FROM article a LEFT JOIN user u ON a.author_id = u.id LEFT JOIN category c ON a.category_id = c.id WHERE a.author_id = #{userId}
AND a.status = #{status}
ORDER BY a.create_time DESC

SELECT , u.nickname as author_name, u.avatar as author_avatar, c.name as category_name FROM article a LEFT JOIN user u ON a.author_id = u.id LEFT JOIN category c ON a.category_id = c.id
INNER JOIN article_tag at ON a.id = at.article_id
a.status = 1 AND a.publish_time >= DATE_SUB(NOW(), INTERVAL 7 DAY)
AND a.category_id = #{queryDTO.categoryId}
AND at.tag_id = #{queryDTO.tagId}
ORDER BY a.is_top DESC, a.publish_time DESC
